output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
SELECT ?currentTeam ?currentTeamLabel WHERE {
  ?player p:P54 [ ps:P54 wd:Q395541 ; pq:P582 ?endDate ] .
  FILTER(year(?endDate) = 2019)
  ?player wdt:P19 wd:Q49229 .
  ?player p:P54 ?currentStatement .
  ?currentStatement ps:P54 ?currentTeam .
  FILTER NOT EXISTS {
    ?currentStatement pq:P582 ?endDt
  }
  OPTIONAL {
    ?currentTeam rdfs:label ?currentTeamLabel
    FILTER(langMatches(LANG(?currentTeamLabel) , 'en'))
  }
}

